class PaymentProcessor {
  static const MethodChannel _channel = MethodChannel('payment_processor');
  final PaymentConfig config;
  final _transactionController = StreamController<PaymentTransaction>.broadcast();

  Stream<PaymentTransaction> get transactionStream => _transactionController.stream;

  PaymentProcessor(this.config) {
    _setupMethodCallHandler();
  }

  void _setupMethodCallHandler() {
    _channel.setMethodCallHandler((call) async {
      switch (call.method) {
        case 'onTransactionUpdate':
          final transaction = PaymentTransaction.fromJson(
            Map<String, dynamic>.from(call.arguments),
          );
          _transactionController.add(transaction);
          break;
      }
    });
  }

  Future<PaymentResult> processCardPayment({
    required CardDetails cardDetails,
    required double amount,
    required String currency,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      if (!cardDetails.isValid()) {
        return PaymentResult(
          success: false,
          errorMessage: 'Invalid card details',
        );
      }

      final token = await _tokenizeCard(cardDetails);
      if (token == null) {
        return PaymentResult(
          success: false,
          errorMessage: 'Card tokenization failed',
        );
      }

      final charge = await _createStripeCharge(
        token: token,
        amount: (amount * 100).toInt(),
        currency: currency,
        metadata: metadata,
      );

      if (charge['status'] == 'succeeded') {
        final transaction = PaymentTransaction(
          id: charge['id'],
          amount: amount,
          currency: currency,
          method: PaymentMethod.creditCard,
          status: PaymentStatus.completed,
          timestamp: DateTime.now(),
          metadata: metadata ?? {},
        );

        _transactionController.add(transaction);

        return PaymentResult(
          success: true,
          transactionId: charge['id'],
          transaction: transaction,
        );
      }

      return PaymentResult(
        success: false,
        errorMessage: 'Payment failed',
      );
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: e.toString(),
      );
    }
  }

  Future<String?> _tokenizeCard(CardDetails cardDetails) async {
    try {
      final response = await http.post(
        Uri.parse('https://api.stripe.com/v1/tokens'),
        headers: {
          'Authorization': 'Bearer ${config.stripePublishableKey}',
